function create(
    address pendleOracle_,
    address pendleMarket_,
    uint32 twapWindow_,
    address priceMiddleware_,
    uint256 usePendleOracleMethod_,
    int256 expextedPriceAfterDeployment_
) external returns (address priceFeedAddress) {
    if (pendleOracle_ == address(0) || pendleMarket_ == address(0) || priceMiddleware_ == address(0)) {
        revert InvalidAddress();
    }

    if (expextedPriceAfterDeployment_ <= 0) {
        revert InvalidExpectedPrice();
    }

    PtPriceFeed ptPriceFeed = new PtPriceFeed(
        pendleOracle_,
        pendleMarket_,
        twapWindow_,
        priceMiddleware_,
        usePendleOracleMethod_
    );

    (, int256 price, , , ) = ptPriceFeed.latestRoundData();

    uint256 expectedPrice = uint256(expextedPriceAfterDeployment_);
    uint256 actualPrice = uint256(price);

    uint256 priceDelta = actualPrice > expectedPrice ? actualPrice - expectedPrice : expectedPrice - actualPrice;

    if (priceDelta * 100 > expectedPrice) {
        revert PriceDeltaTooHigh();
    }

    priceFeedAddress = address(ptPriceFeed);
    emit PtPriceFeedCreated(priceFeedAddress, pendleMarket_);
}

function _deployBeaconProxy(
    bytes32 _salt,
    uint256 _tokenOriginChainId
) internal virtual override returns (BeaconProxy proxy) {
    if (address(L2_LEGACY_SHARED_BRIDGE) == address(0) || _tokenOriginChainId != L1_CHAIN_ID) {
        // Deploy the beacon proxy for the L2 token

        (bool success, bytes memory returndata) = SystemContractsCaller.systemCallWithReturndata(
            uint32(gasleft()),
            L2_DEPLOYER_SYSTEM_CONTRACT_ADDR,
            0,
            abi.encodeCall(
                IContractDeployer.create2,
                (_salt, L2_TOKEN_PROXY_BYTECODE_HASH, abi.encode(address(bridgedTokenBeacon), ""))
            )
        );

        // The deployment should be successful and return the address of the proxy
        if (!success) {
            revert DeployFailed();
        }
        proxy = BeaconProxy(abi.decode(returndata, (address)));
    } else {
        // Deploy the beacon proxy for the L2 token
        address l2TokenAddr = L2_LEGACY_SHARED_BRIDGE.deployBeaconProxy(_salt);
        proxy = BeaconProxy(payable(l2TokenAddr));
    }
}

function registerLegacyChain(uint256 _chainId) external override onlyL1 {
    address ctm = chainTypeManager[_chainId];
    if (ctm == address(0)) {
        revert ChainNotLegacy();
    }
    if (zkChainMap.contains(_chainId)) {
        revert ChainIdAlreadyPresent();
    }

    // From now on, since `zkChainMap` did not contain the chain, we assume
    // that the chain is a legacy chain in the process of migration, i.e.
    // its stored `baseTokenAssetId`, etc.

    address token = __DEPRECATED_baseToken[_chainId];
    if (token == address(0)) {
        revert ChainNotLegacy();
    }

    bytes32 assetId = DataEncoding.encodeNTVAssetId(block.chainid, token);

    baseTokenAssetId[_chainId] = assetId;
    assetIdIsRegistered[assetId] = true;

    address chainAddress = IChainTypeManager(ctm).getZKChainLegacy(_chainId);
    if (chainAddress == address(0)) {
        revert ChainNotPresentInCTM();
    }
    _registerNewZKChain(_chainId, chainAddress, false);
    messageRoot.addNewChain(_chainId);
    settlementLayer[_chainId] = block.chainid;
}

function _assignRole(bytes32 _objectId, bytes32 _contextId, bytes32 _roleId) internal {
    AppStorage storage s = LibAppStorage.diamondStorage();
    require(_objectId != "", "invalid object ID");
    require(_contextId != "", "invalid context ID");
    require(_roleId != "", "invalid role ID");

    bytes32 oldRole = s.roles[_objectId][_contextId];
    if (_contextId == LibAdmin._getSystemId() && oldRole == LibHelpers._stringToBytes32(LibConstants.ROLE_SYSTEM_ADMIN) && oldRole != _roleId) {
        require(s.sysAdmins > 1, "must have at least one system admin");
        unchecked {
            s.sysAdmins -= 1;
        }
    }

    if (_contextId == LibAdmin._getSystemId() && _roleId == LibHelpers._stringToBytes32(LibConstants.ROLE_SYSTEM_ADMIN)) {
        if (LibHelpers._isAddress(_objectId) && LibDiamond.contractOwner() == LibHelpers._getAddressFromId(_objectId)) {
            revert OwnerCannotBeSystemAdmin();
        } else {
            unchecked {
                s.sysAdmins += 1;
            }
        }
    }

    s.roles[_objectId][_contextId] = _roleId;

    emit RoleUpdated(_objectId, _contextId, _roleId, "_assignRole");
}

function _executeFlashLoanPhases(
    address payable onBehalf,
    address payable receiver,
    VToken[] memory vTokens,
    uint256[] memory underlyingAmounts,
    bytes memory param
) internal {
    FlashLoanFee memory flashLoanData;
    //Cache array length
    uint256 vTokensLength = vTokens.length;
    // Initialize arrays
    flashLoanData.totalFees = new uint256[](vTokensLength);
    flashLoanData.protocolFees = new uint256[](vTokensLength);

    // Phase 1: Calculate fees and transfer assets
    _executePhase1(receiver, vTokens, underlyingAmounts, flashLoanData);
    // Phase 2: Execute operations on receiver contract
    uint256[] memory tokensApproved = _executePhase2(
        onBehalf,
        receiver,
        vTokens,
        underlyingAmounts,
        flashLoanData.totalFees,
        param
    );
    // Phase 3: Handles repayment
    _executePhase3(onBehalf, receiver, vTokens, underlyingAmounts, tokensApproved, flashLoanData);
}

function finalizeRequestsUpToIndex(uint256 _lastFinalizedIndex)
        external
        onlyRole(REQUEST_FINALIZER_ROLE)
        returns (uint256 finalizationIndex)
    {

        uint256 currentRate = redemptionAssetsVault.redemptionRate();

        // Create a new Finalization struct
        Finalization memory newFinalization = Finalization({
            startIndex: SafeCast.toUint64(lastFinalizedIndex),
            endIndex: SafeCast.toUint64(_lastFinalizedIndex),
            redemptionRate: SafeCast.toUint96(currentRate)
        });

        finalizationIndex = finalizations.length;

        // Add the new Finalization to the array
        finalizations.push(newFinalization);

        if (_lastFinalizedIndex > _tokenIdCounter) {
            revert IndexExceedsTokenCount(_lastFinalizedIndex, _tokenIdCounter);
        }
        if (_lastFinalizedIndex <= lastFinalizedIndex) {
            revert IndexNotAdvanced(_lastFinalizedIndex, lastFinalizedIndex);
        }
        emit RequestsFinalized(finalizationIndex, _lastFinalizedIndex, lastFinalizedIndex, currentRate);

        lastFinalizedIndex = _lastFinalizedIndex;
    }

