function metaDeposit(
  address depositor,
  address recipient,
  uint256 value,
  uint16 referralCode,
  bool fromUnderlying,
  uint256 deadline,
  SignatureParams calldata sigParams,
  uint256 chainId
) external returns (uint256) {
  require(depositor != address(0), 'INVALID_DEPOSITOR');
  //solium-disable-next-line
  require(block.timestamp <= deadline, 'INVALID_EXPIRATION');
  uint256 currentValidNonce = _nonces[depositor];
  bytes32 digest =
    keccak256(
      abi.encodePacked(
        '\x19\x01',
        getDomainSeparator(chainId),
        keccak256(
          abi.encode(
            METADEPOSIT_TYPEHASH,
            depositor,
            recipient,
            value,
            referralCode,
            fromUnderlying,
            currentValidNonce,
            deadline
          )
        )
      )
    );
  require(
    depositor == ecrecover(digest, sigParams.v, sigParams.r, sigParams.s),
    'INVALID_SIGNATURE'
  );
  _nonces[depositor] = currentValidNonce + 1;
  return _deposit(depositor, recipient, value, referralCode, fromUnderlying);
}

function metaWithdraw(
  address owner,
  address recipient,
  uint256 staticAmount,
  uint256 dynamicAmount,
  bool toUnderlying,
  uint256 deadline,
  SignatureParams calldata sigParams,
  uint256 chainId
) external returns (uint256, uint256) {
  require(owner != address(0), 'INVALID_DEPOSITOR');
  //solium-disable-next-line
  require(block.timestamp <= deadline, 'INVALID_EXPIRATION');
  uint256 currentValidNonce = _nonces[owner];
  bytes32 digest =
    keccak256(
      abi.encodePacked(
        '\x19\x01',
        getDomainSeparator(chainId),
        keccak256(
          abi.encode(
            METAWITHDRAWAL_TYPEHASH,
            owner,
            recipient,
            staticAmount,
            dynamicAmount,
            toUnderlying,
            currentValidNonce,
            deadline
          )
        )
      )
    );
  require(owner == ecrecover(digest, sigParams.v, sigParams.r, sigParams.s), 'INVALID_SIGNATURE');
  _nonces[owner] = currentValidNonce + 1;
  return _withdraw(owner, recipient, staticAmount, dynamicAmount, toUnderlying);
}

function setBytesTransiently(bytes memory _data, bool _takeFeeFromPosition) internal {
    uint256 dataLength = _data.length;

    // ensure data follows abi specification, so length will be multiple of 32 when using abi.encode
    require(dataLength >= 32 && dataLength % 32 == 0);

    // write flag to first slot to indicate if fee is taken from position or EOA/wallet
    uint256 flag = _takeFeeFromPosition ? POSITION_FEE_FLAG : EOA_OR_WALLET_FEE_FLAG;
    assembly {
        tstore(0, flag)
    }

    // write length of _data to second slot
    assembly {
        tstore(1, dataLength)
    }

    // calculate how many slots at full size are we going to use
    uint256 chunks = dataLength / 32;
    uint256 i = 1;
    // write _data split into bytes32 from slot 2 to slot 2+chunks
    for (i; i <= chunks; ++i) {
        uint256 slot = i + 1;
        bytes32 chunk;
        assembly {
            chunk := mload(add(_data, mul(0x20, i))) // chunks are bytes32: _data[0:32] -> _data[32:64] -> etc
            tstore(slot, chunk)
        }
    }
}

function _receiveAndSwapToMint(
    address from,
    uint256 amountIn
) internal returns (uint256) {
    // First, pull tokens to this contract
    IERC20 token = IERC20(from);
    require(
        token.allowance(_msgSender(), address(this)) >= amountIn,
        "NOT_ENOUGH_ALLOWANCE"
    );
    IERC20(from).safeTransferFrom(_msgSender(), address(this), amountIn);

    // Approve infinitely to this contract
    if (token.allowance(address(this), address(BOND)) < amountIn) {
        require(
            token.approve(
                address(BOND),
                0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff
            ),
            "APPROVE_FAILED"
        );
    }

    // Sell tokens to MINT
    // NOTE: ignore minRefund (set as 0) for now, we should check it later on zapOut
    BOND.sell(from, amountIn, 0, DEFAULT_BENEFICIARY);
    IERC20 mintToken = IERC20(MINT_CONTRACT);

    return mintToken.balanceOf(address(this));
}

